      <ProfilePanel 
        user={user} 
        isOpen={isProfileOpen} 
        onClose={() => setIsProfileOpen(false)} 
        onUpdate={onUpdateUser}
      />

      {/* Support Orb */}
      <div className="fixed bottom-8 right-8 z-40">
