  );
};

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>('LANDING');
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [appState]);

  const handleLoginSuccess = (userData: User) => {
    // Identity verification state is initialized based on auth context
    const initialUser = {
      ...userData,
      identity_status: DocumentStatus.VERIFIED,
      accreditation_status: DocumentStatus.NOT_UPLOADED,
    };

    setUser(initialUser);
    if (userData.onboarded) {
      setAppState('PORTAL');
    } else {
      setAppState('ONBOARDING');
    }
  };

  const handleOnboardingComplete = () => {
    if (user) {
      setUser({ ...user, onboarded: true });
      setAppState('PORTAL');
    }
  };

  const handleLogout = () => {
    setUser(null);
    setAppState('LANDING');
  };

  const handleUpdateUser = (data: Partial<User>) => {
    if (user) {
      setUser({ ...user, ...data });
    }
  };

  if (appState === 'LANDING') return <LandingPage onStart={() => setAppState('AUTH')} />;
  if (appState === 'AUTH') return <Auth onSuccess={handleLoginSuccess} onBack={() => setAppState('LANDING')} />;
  if (appState === 'ONBOARDING' && user) return <Onboarding user={user} onComplete={handleOnboardingComplete} />;
  if (appState === 'PORTAL' && user) return <Portal user={user} onLogout={handleLogout} onUpdateUser={handleUpdateUser} />;

  return null;
};

export default App;

