               </div>
               <Button type="submit" className="w-full py-4 uppercase tracking-[0.2em] text-sm bg-[#00E0C6] hover:bg-[#00E0C6]/80 text-[#081C3A]">Create Investment Ledger</Button>
            </form>
          </Card>
        </div>
      )}
    </div>
  );
};

